            return restTemplate.getForObject(url, String.class);
        } catch (ResourceAccessException e) {
            throw new RuntimeException("Failed to fetch URL: " + url, e);
        }
    }

    /**
     * Validates the URL to prevent security vulnerabilities.
     *
     * @param url The URL to validate
     * @throws IllegalArgumentException if the URL is invalid or not allowed
     */
    private void validateUrl(String url) {
        if (url == null || url.trim().isEmpty()) {
            throw new IllegalArgumentException("URL cannot be null or empty");
        }

        try {
            URL parsedUrl = new URL(url);
            String scheme = parsedUrl.getProtocol().toLowerCase();

            if (!ALLOWED_SCHEMES.contains(scheme)) {
                throw new IllegalArgumentException("Only HTTP and HTTPS schemes are allowed");
            }

            String host = parsedUrl.getHost();
            if (host == null || host.isEmpty()) {
                throw new IllegalArgumentException("Invalid URL host");
            }

            if (isPrivateOrInternalAddress(host)) {
                throw new IllegalArgumentException("Access to internal addresses is not allowed");
            }
        } catch (Exception e) {
            throw new IllegalArgumentException("Invalid URL format: " + url, e);
        }
    }

    /**
     * Checks if the host is a private or internal IP address.
     *
     * @param host The hostname or IP address to check
     * @return true if the address is private/internal, false otherwise
     */
    private boolean isPrivateOrInternalAddress(String host) {
        try {
            InetAddress[] addresses = InetAddress.getAllByName(host);
            for (InetAddress addr : addresses) {
                if (addr.isAnyLocalAddress() ||
                    addr.isLoopbackAddress() ||
                    addr.isSiteLocalAddress() ||
                    addr.isLinkLocalAddress()) {
                    return true;
                }
            }
            return false;
        } catch (Exception e) {
            return false;
        }
    }
}
